@app.post("/api/evaluate")
def evaluate(request):
    partner = request.headers.get("X-Partner-ID")
    policy = db.get_policy(partner)
    return ev.evaluate(
        **request.json,
        thresholds=policy["block"],
        flag_thresholds=policy["flag"],
        fallback_messages=policy["fallback"],
    )
